import os

def parse_theta_results(fname):
    with open(fname) as handle:
        lines = [line.strip() for line in handle if line.strip()]
    if len(lines) < 2:
        raise ValueError('File must contain at least a header and a data line')
    header = lines[0].split('\t')
    body = lines[1].split('\t')
    while len(body) < 4:
        body.append('')
    nll_str = body[0].strip()
    if nll_str == '':
        raise ValueError('NLL must not be empty')
    nll = float(nll_str)
    mu_str = body[1].strip()
    if mu_str == '':
        mu_normal = None
        mu_tumors = []
    else:
        mu_parts = mu_str.split(',')
        mu_normal = float(mu_parts[0]) if mu_parts[0] else None
        mu_tumors = [float(x) for x in mu_parts[1:] if x]
    n_tumors = len(mu_tumors)
    def to_int_or_none(s):
        s = s.strip()
        if s == '':
            return None
        try:
            return int(s)
        except ValueError:
            return None
    def to_float_or_none(s):
        s = s.strip()
        if s == '':
            return None
        try:
            return float(s)
        except ValueError:
            return None
    C_str = body[2].strip()
    if C_str == '':
        copies = []
    else:
        groups = C_str.split(':')
        if n_tumors == 0:
            copies = [ [to_int_or_none(g) for g in groups] ]
        else:
            split_groups = [g.split(',') for g in groups]
            for sg in split_groups:
                if len(sg) != n_tumors:
                    print('ValueError caught')
                    return {}
            copies = [ [to_int_or_none(sg[i]) for sg in split_groups] for i in range(n_tumors) ]
    p_str = body[3].strip()
    if p_str == '':
        probs = []
    else:
        probs_flat = p_str.split(',')
        if n_tumors == 0:
            probs = [to_float_or_none(p) for p in probs_flat]
        else:
            probs = [ [to_float_or_none(p) for p in probs_flat] ]
    return {'NLL': nll, 'mu_normal': mu_normal, 'mu_tumors': mu_tumors, 'C': copies, 'p*': probs}
